arguments.command:
cd /tmp/sv-5f88844629e549a9900fc30ed51b4336/symbols && \
# Check if those addresses fall within any known symbol using nm
aarch64-linux-gnu-nm -C libmonosgen-2.0.so.dbg 2>/dev/null | awk '$1 != "" {print}' | sort | awk -v addr1="0x2f4b20" -v addr2="0x2f4c84" '
BEGIN { target1 = strtonum(addr1); target2 = strtonum(addr2) }
/^[0-9a-f]/ {
    cur = strtonum("0x"$1)
    if (prev_addr > 0) {
        if (prev_addr <= target1 && cur > target1) print addr1 " -> " prev_name " + " (target1 - prev_addr)
        if (prev_addr <= target2 && cur > target2) print addr2 " -> " prev_name " + " (target2 - prev_addr)
    }
    prev_addr = cur
    prev_name = $3
}' | head -10

