toolCalls.args:
{"command": "cd /tmp/sv-5f88844629e549a9900fc30ed51b4336/symbols && \
# Use readelf to find functions containing these addresses
aarch64-linux-gnu-readelf -s libmonosgen-2.0.so.dbg | awk '
$4 == "FUNC" && $7 != "UND" {
    addr = strtonum("0x"$2)
    size = strtonum($3)
    if (addr <= 0x2f4b20 && (addr + size) > 0x2f4b20) print "0x2f4b20 in: " $8 " (base: 0x"$2", size: "$3")"
    if (addr <= 0x2f4c84 && (addr + size) > 0x2f4c84) print "0x2f4c84 in: " $8 " (base: 0x"$2", size: "$3")"
}'", "description": "Find enclosing functions for SGen addresses"}

